-- Generated by AutomateDV (formerly known as dbtvault)

    

WITH source_data AS (
    SELECT a.EMPLOYEE_PK, a.EMPLOYEE_HASHDIFF, a.EMP_NM, a.SEX, a.BIRTHDAY, a.EFFECTIVE_FROM, a.LOAD_DATE, a.RECORD_SOURCE
    FROM S45969_DBT_DB.S45969_DBT_AH_SCHEMA.v_stg_employee AS a
    WHERE a.EMPLOYEE_PK IS NOT NULL
),

latest_records AS (
    SELECT a.EMPLOYEE_PK, a.EMPLOYEE_HASHDIFF, a.LOAD_DATE
    FROM (
        SELECT current_records.EMPLOYEE_PK, current_records.EMPLOYEE_HASHDIFF, current_records.LOAD_DATE,
            RANK() OVER (
               PARTITION BY current_records.EMPLOYEE_PK
               ORDER BY current_records.LOAD_DATE DESC
            ) AS rank
        FROM S45969_DBT_DB.S45969_DBT_AH_SCHEMA.sat_employee AS current_records
            JOIN (
                SELECT DISTINCT source_data.EMPLOYEE_PK
                FROM source_data
            ) AS source_records
                ON current_records.EMPLOYEE_PK = source_records.EMPLOYEE_PK
    ) AS a
    WHERE a.rank = 1
),

records_to_insert AS (
    SELECT DISTINCT stage.EMPLOYEE_PK, stage.EMPLOYEE_HASHDIFF, stage.EMP_NM, stage.SEX, stage.BIRTHDAY, stage.EFFECTIVE_FROM, stage.LOAD_DATE, stage.RECORD_SOURCE
    FROM source_data AS stage
    LEFT JOIN latest_records
    ON latest_records.EMPLOYEE_PK = stage.EMPLOYEE_PK
        AND latest_records.EMPLOYEE_HASHDIFF = stage.EMPLOYEE_HASHDIFF
    WHERE latest_records.EMPLOYEE_HASHDIFF IS NULL
)

SELECT * FROM records_to_insert